     3→import { useEffect, useMemo } from 'react';
     4→import { useThree } from '@react-three/fiber';
     5→import { OrbitControls, useTexture } from '@react-three/drei';
     6→import * as THREE from 'three';
     7→import type { VRScene as VRSceneType } from '@/types/vr';
     8→
     9→/**
    10→ * Props for the VRScene component
    11→ */
    12→interface VRSceneProps {
    13→  /** Scene data containing environment and configuration */
    14→  scene: VRSceneType;
    15→  /** Whether to enable orbit controls for camera movement */
    16→  enableControls?: boolean;
    17→  /** Whether this is being viewed in VR mode */
    18→  isVRMode?: boolean;
    19→  /** Callback when scene is loaded */
    20→  onLoad?: () => void;
    21→  /** Callback when texture loading fails */
    22→  onError?: (error: Error) => void;
    23→  /** Override default sphere radius */
    24→  sphereRadius?: number;
    25→}
    26→
    27→/**
    28→ * VRScene Component
    29→ *
    30→ * Displays 360-degree equirectangular images as immersive environments.
    31→ * Creates a large sphere with inward-facing geometry to display panoramic images.
    32→ *
    33→ * Features:
    34→ * - 360-degree panoramic image display
    35→ * - Camera controls for looking around
    36→ * - Configurable lighting based on scene settings
    37→ * - Support for VR and non-VR modes
    38→ * - Automatic texture loading and error handling
    39→ *
    40→ * @example
    41→ * ```tsx
    42→ * <VRScene
    43→ *   scene={sceneData}
    44→ *   enableControls={true}
    45→ *   onLoad={() => console.log('Scene loaded')}
    46→ * />
    47→ * ```
    48→ */
    49→export function VRScene({
    50→  scene,
    51→  enableControls = true,
    52→  isVRMode = false,
    53→  onLoad,
    54→  onError,
    55→  sphereRadius = 500,
    56→}: VRSceneProps) {
    57→  const { camera, gl } = useThree();
    58→
    59→  // Load 360 image texture if available
    60→  const texture = scene.imageUrl
    61→    ? // eslint-disable-next-line react-hooks/rules-of-hooks
    62→      useTexture(scene.imageUrl, (loadedTexture) => {
    63→        // Configure texture for optimal 360 display
    64→        if (loadedTexture instanceof THREE.Texture) {
    65→          loadedTexture.colorSpace = THREE.SRGBColorSpace;
    66→          loadedTexture.mapping = THREE.EquirectangularReflectionMapping;
    67→        }
    68→        onLoad?.();
    69→      })
    70→    : null;
    71→
    72→  // Apply initial camera rotation if specified
    73→  useEffect(() => {
    74→    if (scene.camera?.initialRotation) {
    75→      const { x, y, z } = scene.camera.initialRotation;
    76→      camera.rotation.set(x, y, z);
    77→    }
    78→  }, [scene.camera?.initialRotation, camera]);
    79→
    80→  // Configure camera settings
    81→  useEffect(() => {
    82→    if (scene.camera?.enableZoom !== undefined) {
    83→      // Store zoom preference for controls
    84→      (camera as any).__zoomEnabled = scene.camera.enableZoom;
    85→    }
    86→  }, [scene.camera?.enableZoom, camera]);
    87→
    88→  // Create lighting configuration
    89→  const lighting = useMemo(() => {
    90→    const lights = scene.lighting || {};
    91→    return {
    92→      ambientIntensity: lights.ambientIntensity ?? 0.6,
    93→      ambientColor: lights.ambientColor ?? '#ffffff',
    94→      directionalIntensity: lights.directionalIntensity ?? 0.8,
    95→      directionalColor: lights.directionalColor ?? '#ffffff',
    96→      directionalPosition: lights.directionalPosition ?? { x: 5, y: 10, z: 5 },
    97→    };
    98→  }, [scene.lighting]);
    99→
   100→  // Handle texture loading errors
   101→  useEffect(() => {
   102→    if (!scene.imageUrl) return;
   103→
   104→    const handleError = (error: ErrorEvent) => {
   105→      if (onError) {
   106→        onError(new Error(`Failed to load scene image: ${error.message}`));
   107→      }
   108→    };
   109→
   110→    gl.domElement.addEventListener('error', handleError);
   111→    return () => {
   112→      gl.domElement.removeEventListener('error', handleError);
   113→    };
   114→  }, [scene.imageUrl, gl.domElement, onError]);
   115→
   116→  return (
   117→    <>
   118→      {/* Lighting Setup */}
   119→      <ambientLight intensity={lighting.ambientIntensity} color={lighting.ambientColor} />
   120→      <directionalLight
   121→        intensity={lighting.directionalIntensity}
   122→        color={lighting.directionalColor}
   123→        position={[
   124→          lighting.directionalPosition.x,
   125→          lighting.directionalPosition.y,
   126→          lighting.directionalPosition.z,
   127→        ]}
   128→        castShadow
   129→      />
   130→
   131→      {/* 360 Panoramic Sphere */}
   132→      {scene.environmentType === '360-image' && scene.imageUrl && texture && (
   133→        <mesh>
   134→          <sphereGeometry args={[sphereRadius, 60, 40]} />
   135→          <meshBasicMaterial
   136→            map={texture}
   137→            side={THREE.BackSide} // Render inside of sphere
   138→            toneMapped={false}
   139→          />
   140→        </mesh>
   141→      )}
   142→
   143→      {/* Fallback background color if no image */}
   144→      {(!scene.imageUrl || scene.environmentType !== '360-image') && (
   145→        <color attach="background" args={['#87CEEB']} />
   146→      )}
   147→
   148→      {/* Camera Controls - disabled in VR mode as headset handles it */}
   149→      {enableControls && !isVRMode && (
   150→        <OrbitControls
   151→          enableZoom={scene.camera?.enableZoom ?? true}
   152→          enablePan={false}
   153→          enableDamping={true}
   154→          dampingFactor={0.05}
   155→          rotateSpeed={-0.5} // Negative to invert rotation for natural feel
   156→          minDistance={scene.camera?.zoomRange?.min ?? 1}
   157→          maxDistance={scene.camera?.zoomRange?.max ?? 10}
   158→          minPolarAngle={scene.camera?.minPolarAngle ?? 0}
   159→          maxPolarAngle={scene.camera?.maxPolarAngle ?? Math.PI}
   160→          target={[0, 0, 0]}
   161→        />
   162→      )}
   163→    </>
   164→  );
   165→}
   166→
   167→/**
   168→ * VRSceneLoading Component
   169→ *
   170→ * Placeholder component shown while scene assets are loading
   171→ */
   172→export function VRSceneLoading() {
   173→  return (
   174→    <>
   175→      <ambientLight intensity={0.5} />
   176→      <color attach="background" args={['#1a1a1a']} />
   177→      {/* Simple animated sphere to indicate loading */}
   178→      <mesh>
   179→        <sphereGeometry args={[2, 32, 32]} />
   180→        <meshStandardMaterial color="#4a5568" wireframe />
   181→      </mesh>
   182→    </>
   183→  );
   184→}
   185→
   186→export default VRScene;
   187→

